INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L2_B', 'PS2h', 2, 'B', 'Oral->Written Word Manipulation', 'Paper, Pencil', 'Write the root word ''hope''. Now, we want to add the suffix ''-ful''. Remember, when the root ends in a magic ''e'' and the suffix starts with a consonant, we just stick them together. Write ''hopeful''.', 'Child writes ''hope'', says ''hopeful'', and writes ''hopeful''.', 'If they drop the ''e'' (''hopful''), remind them of the rule.', 'Did we keep the ''e'' or drop it? Why?', '{"default":{"words":[["hope","hopeful"],["care","careless"]]},"ug":{"words":[["hope","hopeful"],["care","careless"]]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L2_C', 'PS2h', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Listen to this sentence: ''He was very helpful.'' Say it back to me, then write it down.', 'Child repeats and spells ''helpful'' correctly, identifying root and suffix.', 'If they misspell ''helpful'' (e.g., ''helpfull''), point out that the suffix ''-ful'' only has one ''l''.', 'What is the root word in ''helpful''? What is the suffix?', '{"default":{"sentences":["He was very helpful."]},"ug":{"sentences":["He was very helpful."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L3_A', 'PS2h', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Look at this sentence: ''The puppy is very playfull.'' Find the mistake in how the suffix is spelled.', 'Child identifies that the suffix ''-ful'' should only have one ''l''.', 'If they miss it, write ''full'' and ''-ful'' side by side and explain the difference.', 'When ''-ful'' is attached to a word as a suffix, how many ''l''s does it have?', '{"default":{"sentence":"The puppy is very playfull.","error":"playfull","fix":"playful"},"ug":{"sentence":"The dog is very playfull.","error":"playfull","fix":"playful"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L3_B', 'PS2h', 3, 'B', 'Auditory Error Detection', 'None', 'Listen to this sentence: ''I tied my shoes, but then I had to re-tie them because I did it wrong.'' Does ''re-tie'' make sense there? What does ''re-'' mean?', 'Child confirms ''re-tie'' makes sense and means ''tie again''.', 'If they say ''un-tie'', explain: ''If I did it wrong, I want to do it again (re-), not undo it (un-).''', 'If I wanted to take my shoes off, what prefix would I use instead of ''re-''?', '{"default":{"word":"re-tie","meaning":"tie again"},"ug":{"word":"re-tie","meaning":"tie again"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L3_C', 'PS2h', 3, 'C', 'Visual Discrimination', 'Paper with printed words', 'Here are three words: ''unlock'', ''under'', ''unhappy''. Two of these words have the prefix ''un-''. One of them just starts with the letters ''u-n'' but doesn''t have a prefix. Which one is the trick word?', 'Child identifies ''under'' because ''der'' is not a root word.', 'If they struggle, ask them to read the root word of each (lock, der, happy).', 'Why isn''t ''un-'' a prefix in the word ''under''?', '{"default":{"options":["unlock","under","unhappy"],"target":"under"},"ug":{"options":["unlock","under","unhappy"],"target":"under"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L4_A', 'PS2h', 4, 'A', 'Creative Production', 'Paper, Pencil', 'Write the prefix ''un-'' at the top of your page. Now, list three root words that you can add ''un-'' to, to make real words (like ''un-do'' or ''un-lock''). Write the full words.', 'Child successfully lists three valid words starting with ''un-''.', 'If they list words like ''under'' or ''uncle'', remind them to check if the root is a real word.', 'Cover up the ''un-'' in each of your words. Are the words underneath real words?', '{"default":{"prefix":"un-"},"ug":{"prefix":"un-"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L4_B', 'PS2h', 4, 'B', 'Sentence Creation', 'Paper, Pencil', 'Think of a word that ends with the suffix ''-less'' (like ''careless'' or ''fearless''). Tell me a sentence using that word, and then write it down.', 'Child composes and writes a sentence utilizing a word ending in ''-less''.', 'If they don''t know the meaning, remind them that ''-less'' means ''without''.', 'What does your word mean in that sentence? (e.g., fearless = without fear).', '{"default":{"suffix":"-less"},"ug":{"suffix":"-less"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L4_C', 'PS2h', 4, 'C', 'Instructional Production', 'Paper, Pencil', 'Explain the difference between a prefix (like ''re-'') and a suffix (like ''-ful''). Where do they go on a root word, and what do they do? Write an example of each.', 'Child explains that prefixes go at the beginning, suffixes at the end, and both change the meaning of the root.', 'If they get confused, have them draw a train with an engine (prefix), car (root), and caboose (suffix).', 'How does adding an affix change a word?', '{"default":{"concept":"prefix vs suffix"},"ug":{"concept":"prefix vs suffix"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2h_L4_M', 'PS2h', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'Write a short note telling someone not to do something again. Use a word that starts with the prefix ''re-'' (like ''rebuild'', ''rewrite'', or ''remake''). Say the sentence, then write it.', 'Child orally composes and accurately writes a sentence using a word with the prefix ''re-''.', 'Do not correct during the task. If spelling or concept fails, review Execute level tasks.', 'Show me the word with the prefix. What is the root word hiding inside it?', '{"default":{"constraint":"use ''re-'' prefix"},"ug":{"constraint":"use ''re-'' prefix"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L1_A', 'PS2i', 1, 'A', 'Auditory Discrimination', 'None', 'Listen to this sentence: ''I was going to the store.'' Listen again: ''I was going to the store.'' Which word sounds like /wuz/?', 'Child identifies ''was''.', 'If they say ''wuz'' is not in the sentence, repeat the sentence slowly.', 'Why is ''was'' a tricky word to spell?', '{"default":{"sentence":"I was going to the store."},"ug":{"sentence":"I was going to the shop."}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L1_B', 'PS2i', 1, 'B', 'Physical Manipulation', 'Paper, Pencil or finger', 'Look at the word ''said''. It is a tricky word because it doesn''t follow the rules. Trace the letters with your finger while you spell it out loud: s-a-i-d. What does it say?', 'Child traces the letters and reads ''said''.', 'If they try to sound it out phonetically (/s/ /a/ /i/ /d/), remind them it''s a ''heart word'' we have to memorize by heart.', 'Which part of the word ''said'' is the tricky part?', '{"default":{"word":"said"},"ug":{"word":"said"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L1_C', 'PS2i', 1, 'C', 'Visual Discrimination', 'A book or printed text', 'Look at this page in your book. The word ''they'' is spelled t-h-e-y. It''s very common. See how many times you can find the word ''they'' on this page in one minute.', 'Child locates the word ''they'' multiple times.', 'If they miss it, write ''they'' big on a piece of paper to act as a model to match.', 'How do you spell the word ''they''?', '{"default":{"word":"they"},"ug":{"word":"they"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L2_A', 'PS2i', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I am going to say a tricky sight word. Say the letters out loud as you write it. The word is ''could''. (c-o-u-l-d).', 'Child writes ''could'' from memory.', 'If misspelled, show them the correct spelling, have them trace it 3 times saying the letters, then hide it and try again.', 'What are the tricky silent letters in the middle of ''could''?', '{"default":{"words":["could","would","should"]},"ug":{"words":["could","would","should"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L2_B', 'PS2i', 2, 'B', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Listen to this sentence: ''They went to the park.'' Say it back, then write it.', 'Child accurately spells the high-frequency words ''they'', ''went'', ''to'', ''the''.', 'If ''they'' is spelled ''thay'', review the specific spelling of ''they''.', 'Point to the word ''they''. How did you spell it?', '{"default":{"sentences":["They went to the park.","He said to come here."]},"ug":{"sentences":["They went to the park.","He said to come here."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L2_C', 'PS2i', 2, 'C', 'Visual Memory Dictation', 'Paper, Pencil, Flashcard with the word ''because''', 'Look at the word ''because''. I''m going to hide it in 3 seconds. Try to take a picture of it in your brain. 1... 2... 3... (hide it). Now write it down.', 'Child writes ''because'' accurately from visual memory.', 'If misspelled, show the card again, point out the tricky part (a-u-s-e), and try again.', 'What trick helps you remember how to spell ''because''?', '{"default":{"words":["because","people","friend"]},"ug":{"words":["because","people","friend"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L3_A', 'PS2i', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Read this sentence: ''My f-r-e-n-d is nice.'' That word is spelled how it sounds, but it''s a tricky word so that spelling is wrong. How do we actually spell ''friend''?', 'Child identifies the missing ''i'' and spells ''friend''.', 'If they don''t know, write it out for them: ''f-r-i-e-n-d''.', 'Why can''t we just sound out the word ''friend''?', '{"default":{"sentence":"My frend is nice.","error":"frend","fix":"friend"},"ug":{"sentence":"My frend is nice.","error":"frend","fix":"friend"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L3_B', 'PS2i', 3, 'B', 'Auditory Error Detection', 'None', 'Listen to this: ''I have two eyes, so I can see.'' Now listen to this: ''I went two the store.'' Did I use the right ''two/to/too'' in both sentences?', 'Child identifies that ''went two the store'' is incorrect in meaning/spelling.', 'If they miss the homophone difference, explain two (number), too (also), and to (direction).', 'Which ''to'' means direction?', '{"default":{"sentences":["I went two the store.","I went to the store."]},"ug":{"sentences":["I went two the shop.","I went to the shop."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L3_C', 'PS2i', 3, 'C', 'Visual Discrimination', 'Paper with printed words', 'Which is the correct way to spell the word that means a group of humans: ''peeple'' or ''people''?', 'Child selects ''people''.', 'If they choose ''peeple'', remind them it''s a ''heart word'' that doesn''t follow the normal ''ee'' rule.', 'What are the tricky vowels in the middle of the word ''people''?', '{"default":{"options":["peeple","people"]},"ug":{"options":["peeple","people"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L4_A', 'PS2i', 4, 'A', 'Creative Production', 'Paper, Pencil', 'Think of three tricky sight words that you can''t just sound out perfectly (like ''was'', ''said'', or ''they''). Say them, then write them down from memory.', 'Child lists three non-phonetic high-frequency words.', 'If they write phonetic words (like ''cat''), ask: ''Can you sound out every letter in cat perfectly? Yes. Find a word where the letters lie to you.''', 'Pick one of your words. Which part of it is tricky?', '{"default":{"constraint":"non-phonetic words"},"ug":{"constraint":"non-phonetic words"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L4_B', 'PS2i', 4, 'B', 'Sentence Creation', 'Paper, Pencil', 'Tell me a sentence using the word ''their'' (like ''their dog''). Then tell me a sentence using the word ''there'' (like ''over there''). Write both sentences.', 'Child orally composes and writes sentences using correct contextual spelling of there/their.', 'If they confuse them, review: ''their'' has an ''i'' for ''heir/person''; ''there'' has ''here'' inside it.', 'How do you remember which spelling to use for ''over there''?', '{"default":{"target":"there vs their"},"ug":{"target":"there vs their"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L4_C', 'PS2i', 4, 'C', 'Creative Story', 'Paper, Pencil', 'Write a short, two-sentence story. You must use the words ''because'' and ''friend'' in your story. Tell it to me first, then write it.', 'Child orally composes and writes a short story utilizing and correctly spelling the target words.', 'If they misspell the target words, have them erase and correct just those words.', 'Point to the word ''because''. Read the letters to me.', '{"default":{"words":["because","friend"]},"ug":{"words":["because","friend"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2i_L4_M', 'PS2i', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'We need to write a quick note to a friend. Write: ''I like you because you are fun.'' Say it out loud, then write it.', 'Child accurately spells the high-frequency words ''you'', ''because'', ''are''.', 'Do not correct during the task. If spelling fails heavily, review Execute level tasks.', 'Show me the word ''because'' on your note. How did you remember the tricky parts?', '{"default":{"sentence":"I like you because you are fun."},"ug":{"sentence":"I like you because you are fun."}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L1_A', 'PS2j', 1, 'A', 'Auditory Discrimination', 'None', 'I''m going to say a big word: ''trumpet''. Let''s count the sounds we hear in the first chunk, ''trum''. T-r-u-m. How many sounds is that?', 'Child identifies 4 individual sounds.', 'If they say 1 or 2, stretch the sounds out very slowly while holding up a finger for each one.', 'What is the very first sound in ''trum''? What is the last sound?', '{"default":{"word":"trumpet"},"ug":{"word":"trumpet"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L1_B', 'PS2j', 1, 'B', 'Physical Manipulation', '4 small items (coins, blocks, or drawn boxes on paper)', 'We are going to map the word ''frog''. Say the word slowly and push a coin forward for every sound you hear: /f/ /r/ /o/ /g/. How many coins did you push?', 'Child pushes 4 coins, one for each phoneme.', 'If they push one coin for ''fr'', remind them that a blend is two separate sounds pushed together.', 'Which sound does the second coin stand for?', '{"default":{"word":"frog","phonemes":4},"ug":{"word":"frog","phonemes":4}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L1_C', 'PS2j', 1, 'C', 'Visual Discrimination', 'Paper with printed words', 'Look at the word ''s-w-i-m''. Read the letters out loud. Does that word have all the sounds we need to say ''swim''?', 'Child confirms yes.', 'If they are confused, point to each letter while saying the sounds slowly.', 'What sound does the ''w'' make in that word?', '{"default":{"word":"swim"},"ug":{"word":"swim"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L2_A', 'PS2j', 2, 'A', 'Oral->Written Dictation', 'Paper, Pencil', 'I am going to say a word you might not know how to spell. But you can figure it out. The word is ''pumpkin''. Say the first chunk (''pump''), say the sounds, write it. Then the next chunk (''kin'').', 'Child accurately segments and writes ''pumpkin''.', 'If they miss the ''p'' in ''pump'', have them stretch the sounds again: p-u-m-p.', 'How did breaking the word into chunks help you spell it?', '{"default":{"words":["pumpkin","plastic"]},"ug":{"words":["plastic","dustbin"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L2_B', 'PS2j', 2, 'B', 'Oral->Written Word Building', 'Paper, Pencil', 'Draw four little lines on your paper like this: _ _ _ _. We are going to spell ''stop''. What is the first sound? Write the letter on the first line. Next sound? Write it.', 'Child maps the 4 phonemes to the 4 lines accurately to spell ''stop''.', 'If they struggle, say the word extremely slowly so they hear every distinct sound.', 'Why do we need 4 lines for the word ''stop''?', '{"default":{"words":["stop","jump"]},"ug":{"words":["stop","jump"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L2_C', 'PS2j', 2, 'C', 'Oral->Written Sentence Dictation', 'Paper, Pencil', 'Repeat this sentence: ''The small crab hid in the sand.'' Say it back, then write it.', 'Child encodes complex consonant clusters (sm-, cr-, -nd) and digraphs accurately.', 'If they write ''cab'' for ''crab'', point to the word and ask what sounds are missing.', 'Look at the word ''crab''. Did you remember both sounds at the beginning?', '{"default":{"sentences":["The small crab hid in the sand."]},"ug":{"sentences":["The small crab hid in the sand."]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L3_A', 'PS2j', 3, 'A', 'Error Detection', 'Paper with printed sentence', 'Someone tried to sound out the word ''jump''. They wrote ''j-u-p''. Read that word. What sound did they forget to encode?', 'Child identifies that ''m'' is missing.', 'If they can''t tell, stretch ''jump'' slowly and count the sounds on your fingers.', 'Why is it easy to forget the ''m'' in ''jump''?', '{"default":{"word":"jump","error":"jup","fix":"jump"},"ug":{"word":"jump","error":"jup","fix":"jump"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L3_B', 'PS2j', 3, 'B', 'Auditory Error Detection', 'None', 'Listen: ''I am going to d-r-i-n the water from the cup.'' Did I say ''drink'' correctly? What was missing?', 'Child identifies the missing /k/ sound at the end.', 'If they say yes, emphasize the end of the word ''drin-K''.', 'What letter makes the sound I forgot at the end?', '{"default":{"word":"drink","error":"drin"},"ug":{"word":"drink","error":"drin"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L3_C', 'PS2j', 3, 'C', 'Visual Discrimination', 'Paper with printed words', 'A little kid tried to write the word ''elephant''. They wrote ''e-l-e-f-i-n-t''. It''s not spelled perfectly, but did they do a good job capturing all the sounds they heard?', 'Child confirms yes, it phonetically makes sense.', 'If they just say ''it''s spelled wrong'', explain that encoding is about getting the sounds down first, even if the spelling rules are tricky (like ph for f).', 'Which part did they spell differently from the dictionary, but it still makes the same sound?', '{"default":{"word":"elephant","invented":"elefint"},"ug":{"word":"elephant","invented":"elefint"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L4_A', 'PS2j', 4, 'A', 'Creative Spelling', 'Paper, Pencil', 'I am going to say a very long word you probably haven''t spelled before: ''fantastic''. Break it into chunks. Clap the syllables. Now write it down just by listening to the sounds.', 'Child claps fan-tas-tic and writes ''fantastic'' (or highly accurate phonetic equivalent).', 'If they freeze, guide them: ''What is the first chunk? Fan. Spell fan.''', 'Read the chunks back to me. Did you capture every sound?', '{"default":{"word":"fantastic"},"ug":{"word":"fantastic"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L4_B', 'PS2j', 4, 'B', 'Sentence Creation', 'Paper, Pencil', 'Think of an animal that lives in the ocean (like a shark, a crab, or a dolphin). Tell me a sentence about what it does. Then write it down, sounding out any hard words as best you can.', 'Child orally composes and writes a sentence, utilizing phonetic encoding strategies for unknown words.', 'If they ask ''how do I spell...'', tell them ''Stretch the sounds and write what you hear.''', 'Show me a word you had to stretch out to spell. How did you figure it out?', '{"default":{"theme":"ocean animal"},"ug":{"theme":"lake animal (like a fish or hippo)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L4_C', 'PS2j', 4, 'C', 'Instructional Production', 'Paper, Pencil', 'If your little sibling asks you ''how do you spell blanket?'', what steps would you tell them to follow so they can figure it out themselves?', 'Child articulates strategies: say it slowly, chop it into syllables, listen for each sound, write the letters for those sounds.', 'If they just say ''I would tell them b-l-a...'', remind them they are supposed to teach the *strategy*, not just give the answer.', 'Why is it better to listen to the sounds instead of just trying to memorize every word?', '{"default":{"concept":"how to spell an unknown word"},"ug":{"concept":"how to spell an unknown word"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('PS2j_L4_M', 'PS2j', 4, 'M', 'Milestone Production', 'Paper, Pencil', 'We are making a list of three things you want to do this weekend. Say them out loud to me, then write them down. Don''t worry about perfect spelling—just stretch the sounds and write what you hear.', 'Child orally composes and independently writes a list, demonstrating functional phonetic spelling without freezing or constantly asking for help.', 'Do not correct during the task. The goal is confident, readable phonetic encoding.', 'Read your list back to me. Did you get all the sounds down?', '{"default":{"prompt":"three things you want to do this weekend"},"ug":{"prompt":"three things you want to do this weekend"}}', 0);

-- File: english_band_2_strand_2.json
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L1_A', 'RC2a', 1, 'A', 'Auditory & Visual Comprehension', 'None', 'Read the passage out loud. Ask: ''Who went to the market?''', 'Child correctly identifies the character who went to the market.', 'If incorrect, re-read the first sentence and ask the question again.', 'How do you know that person went to the market?', '{"default":{"character":"Alex","setting":"store"},"ug":{"character":"Amara","setting":"Kampala market"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L1_B', 'RC2a', 1, 'B', 'Physical Pointing', 'A printed copy of the passage', 'Read the passage out loud while pointing to the words. Ask: ''Point to the word that tells us what Amara bought.''', 'Child correctly points to the word ''mangoes''.', 'If incorrect, read the sentence again slowly and guide their finger.', 'What word did you point to?', '{"default":{"item":"apples"},"ug":{"item":"mangoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L1_C', 'RC2a', 1, 'C', 'Verbal Recall', 'None', 'Read the passage out loud. Ask: ''When did Amara go to the market? Morning or afternoon?''', 'Child correctly recalls the time of day from the text.', 'If incorrect, read the sentence mentioning the time again.', 'Did the story say she went in the morning or afternoon?', '{"default":{"time":"morning"},"ug":{"time":"morning"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L2_A', 'RC2a', 2, 'A', 'Written Answer - Who', 'Paper, Pencil, Printed passage', 'Read the passage. Tell me: Who is the main character? Say the answer in a full sentence, then write it.', 'Child writes a full sentence identifying the main character.', 'If incorrect or incomplete, remind them to use a full sentence and check the text.', 'Which sentence in the text tells you the character''s name?', '{"default":{"character":"Sam"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L2_B', 'RC2a', 2, 'B', 'Written Answer - What', 'Paper, Pencil, Printed passage', 'Read the passage. Tell me: What did Tendo plant? Say the answer, then write it.', 'Child writes a full sentence identifying what was planted.', 'If incorrect, prompt them to find the word ''planted'' in the text and read the rest of the sentence.', 'How did you know what he planted?', '{"default":{"item":"beans"},"ug":{"item":"matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L2_C', 'RC2a', 2, 'C', 'Written Answer - Where', 'Paper, Pencil, Printed passage', 'Read the passage. Tell me: Where did Tendo plant the seeds? Say the answer, then write it.', 'Child writes a full sentence identifying the location.', 'If incorrect, prompt them to scan the text for the place.', 'What words in the story told you where he was?', '{"default":{"place":"yard"},"ug":{"place":"garden by Lake Victoria"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L3_A', 'RC2a', 3, 'A', 'Detecting Factual Errors', 'Printed passage', 'Read the passage. I will say a sentence about it: ''Amara bought bananas at the market.'' Is that correct based on the story?', 'Child correctly identifies that the statement is false (she bought mangoes).', 'If they say it''s true, ask them to find the word ''bananas'' in the text.', 'What did she actually buy?', '{"default":{"item":"apples","wrong_item":"oranges"},"ug":{"item":"mangoes","wrong_item":"bananas"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L3_B', 'RC2a', 3, 'B', 'Correcting Statements', 'Printed passage, Paper, Pencil', 'Read the passage. This sentence has a mistake: ''Tendo planted the seeds in the house.'' Tell me the mistake, and then write the corrected sentence.', 'Child correctly rewrites the sentence to state the seeds were planted in the garden.', 'If incorrect, prompt them to check where the story says the seeds were planted.', 'Why is ''in the house'' wrong?', '{"default":{"place":"yard","wrong_place":"house"},"ug":{"place":"garden","wrong_place":"house"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L3_C', 'RC2a', 3, 'C', 'Choosing the Correct Detail', 'Printed passage', 'Read the passage. Which of these is true: A) Amara went to the market in the evening, or B) Amara went to the market in the morning?', 'Child selects the correct option based on the text.', 'If incorrect, ask them to find the word ''morning'' or ''evening'' in the text.', 'Show me exactly where the story says when she went.', '{"default":{"correct":"morning","incorrect":"evening"},"ug":{"correct":"morning","incorrect":"evening"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L4_A', 'RC2a', 4, 'A', 'Creating Questions', 'Printed passage, Paper, Pencil', 'Read the passage. Now, write one ''Who'' question and one ''What'' question about the story to test me.', 'Child writes two valid literal comprehension questions.', 'If questions are not literal or not based on the text, guide them to ask about a specific detail.', 'Can you find the answer to your question right in the text?', '{"default":{"theme":"everyday life"},"ug":{"theme":"everyday life"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L4_B', 'RC2a', 4, 'B', 'Writing a Descriptive Sentence', 'Paper, Pencil', 'Write a short sentence about what you ate for breakfast today. Make sure it tells ''what'' and ''when''.', 'Child writes a complete sentence containing both a ''what'' and a ''when'' detail.', 'If missing a detail, ask: ''Did you tell me what you ate? Did you tell me when?''', 'Which part of your sentence answers the question ''what''?', '{"default":{"meal":"breakfast"},"ug":{"meal":"breakfast (like chapati or porridge)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L4_C', 'RC2a', 4, 'C', 'Explaining Literal Details', 'Printed passage', 'Read the passage to your sibling or me. Then, explain to us exactly what the main character did, using only facts from the story.', 'Child orally recounts the literal actions of the character without adding outside information.', 'If they add details not in the story, remind them to stick only to what the text says.', 'Is that detail written in the story, or did you guess it?', '{"default":{"character":"Alex"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2a_L4_M', 'RC2a', 4, 'M', 'Extracting Facts from a Note', 'Printed note, Paper, Pencil', 'Here is a note from your uncle. Read it. Then write down the answers to these questions: What time is he coming? What is he bringing?', 'Child reads the note and correctly extracts the time and the item.', 'Do not correct during the task. If they struggle significantly, return to Execute level literal comprehension.', 'How did you find the answers in the note?', '{"default":{"relative":"uncle","item":"book"},"ug":{"relative":"Uncle Musa","item":"groundnuts"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L1_A', 'RC2b', 1, 'A', 'Auditory Sequencing', 'None', 'Listen to this short story. ''First, Amara woke up. Next, she ate breakfast. Last, she walked to school.'' What did she do first?', 'Child correctly identifies that Amara woke up first.', 'If incorrect, emphasize the sequence words: First, Next, Last.', 'What word helped you know what happened at the beginning?', '{"default":{"sequence":"woke up, ate, walked"},"ug":{"sequence":"woke up, ate porridge, walked"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L1_B', 'RC2b', 1, 'B', 'Physical Sequencing', '3 picture cards or simple drawings representing the story events', 'I''m going to read a story. Here are three pictures showing what happens. Put the pictures in the correct order: beginning, middle, and end.', 'Child sequences the three pictures correctly.', 'If incorrect, re-read the story slowly and pause at each major event.', 'Why does this picture go in the middle?', '{"default":{"theme":"planting a seed"},"ug":{"theme":"planting matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L1_C', 'RC2b', 1, 'C', 'Verbal Retell Support', 'None', 'I will read a story about Tendo. When I finish, I want you to tell the story back to me. I''ll help by asking: ''What happened first?''', 'Child successfully recounts the first major event of the story.', 'If they struggle, provide the first event and ask what happened next.', 'Who was the story about and what did they do first?', '{"default":{"character":"Sam"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L2_A', 'RC2b', 2, 'A', 'Written Sequence - First', 'Paper, Pencil, Printed passage', 'Read the story. Tell me what happened first. Say it in a complete sentence, then write it.', 'Child writes a sentence describing the initial event.', 'If they describe the middle or end, remind them to look at the very beginning of the story.', 'How do you know this is what happened first?', '{"default":{"event":"woke up"},"ug":{"event":"woke up"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L2_B', 'RC2b', 2, 'B', 'Written Sequence - Next', 'Paper, Pencil, Printed passage', 'Read the story. Tell me what happened in the middle of the story, after the beginning. Say it, then write it.', 'Child writes a sentence describing the middle event.', 'If they describe the end, ask them what happened right after the first event.', 'What word in the story tells you this happened next?', '{"default":{"event":"ate breakfast"},"ug":{"event":"ate chapati"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L2_C', 'RC2b', 2, 'C', 'Written Sequence - Last', 'Paper, Pencil, Printed passage', 'Read the story. Tell me how the story ended. Say it, then write it down.', 'Child writes a sentence describing the concluding event.', 'If they miss the ending, ask them to read the very last sentence again.', 'How did the problem in the story get solved at the end?', '{"default":{"event":"went to school"},"ug":{"event":"walked to school"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L3_A', 'RC2b', 3, 'A', 'Detecting Out-of-Order Retell', 'Printed passage', 'Read the passage. Now listen to my retell: ''First, Tendo found the ball. Then, he lost his ball. Last, he went home.'' Did I tell that in the right order?', 'Child identifies that the sequence is wrong.', 'If they say it''s right, have them look at the text to see which happened first: losing or finding.', 'Why doesn''t my order make sense?', '{"default":{"theme":"losing a ball"},"ug":{"theme":"losing a ball at the pitch"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L3_B', 'RC2b', 3, 'B', 'Identifying Missing Details', 'Printed passage', 'Read the story. Here is my retell: ''Amara went to the market and then went home.'' What important middle detail did I leave out?', 'Child identifies the missing middle action (e.g., buying mangoes).', 'If they can''t find it, ask them to read the middle of the story again.', 'Why is that detail important to the story?', '{"default":{"character":"Alex","detail":"buying apples"},"ug":{"character":"Amara","detail":"buying mangoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L3_C', 'RC2b', 3, 'C', 'Correcting a Retell', 'Printed passage, Paper, Pencil', 'Read the story. I wrote a retell, but I included something that didn''t happen: ''The dog barked at the cat, then chased a car.'' Tell me what is wrong, and write the correct sentence.', 'Child identifies the incorrect event and writes what actually happened.', 'If they struggle, ask them to check if a car is mentioned anywhere in the story.', 'Did the story say anything about a car?', '{"default":{"wrong_event":"chased a car"},"ug":{"wrong_event":"chased a car"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L4_A', 'RC2b', 4, 'A', 'Full Oral Retell', 'Printed passage', 'Read the story silently. Then, put the paper face down and tell me the story in your own words. Make sure to include the beginning, middle, and end.', 'Child provides a complete oral retell including main characters, setting, and key sequence of events.', 'If they miss a major part, prompt them: ''What happened after...? / How did it start?''', 'Did you remember to tell me how the story ended?', '{"default":{"theme":"a day at the park"},"ug":{"theme":"a day at Lake Victoria"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L4_B', 'RC2b', 4, 'B', 'Written Summary', 'Printed passage, Paper, Pencil', 'Read the story. Write a three-sentence summary. One sentence for the beginning, one for the middle, and one for the end. Tell me the sentences before you write.', 'Child writes three sequential sentences summarizing the story.', 'If they focus too much on minor details, ask: ''What was the most important thing that happened in the middle?''', 'Does your summary tell someone the whole story in just a few sentences?', '{"default":{"theme":"finding a lost item"},"ug":{"theme":"finding a lost goat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L4_C', 'RC2b', 4, 'C', 'Story Extension', 'Printed passage, Paper, Pencil', 'Read the story. It tells us the beginning and middle. Think of an ending that makes sense. Tell it to me, then write the ending sentence.', 'Child creates a logical concluding sentence based on the story details.', 'If the ending doesn''t make sense, ask them to review what the problem in the story was.', 'How does your ending fix the problem in the story?', '{"default":{"theme":"cooking dinner"},"ug":{"theme":"cooking matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2b_L4_M', 'RC2b', 4, 'M', 'Message Relay', 'A printed paragraph of instructions', 'Here are instructions for what we need to do this afternoon. Read them. Then put the paper away and tell your sibling (or me) exactly what we need to do, in the right order.', 'Child accurately relays the sequential steps from the text from memory.', 'Do not correct during the task. If they fail significantly, review sequence words and memory retell.', 'Why is it important to tell the steps in the exact right order?', '{"default":{"theme":"cleaning the house"},"ug":{"theme":"sweeping the compound"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L1_A', 'RC2c', 1, 'A', 'Auditory Main Idea', 'None', 'I''m going to read a short passage. ''Birds build nests. They lay eggs in them. The eggs hatch into baby birds.'' Is this mostly about eggs, or mostly about how birds have babies?', 'Child correctly identifies the broader topic (how birds have babies/bird life cycle).', 'If they say eggs, ask: ''Does the first sentence talk about eggs?''', 'How do you know it''s not JUST about eggs?', '{"default":{"topic":"birds"},"ug":{"topic":"birds"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L1_B', 'RC2c', 1, 'B', 'Visual Categorization', 'Printed passage, 3 picture cards (one representing the main idea, two representing details)', 'Read this paragraph. Look at these three pictures. Point to the picture that shows what the WHOLE paragraph is mostly about, not just one little part.', 'Child selects the picture representing the main idea.', 'If they pick a detail picture, ask: ''Is the whole story about this one thing, or is it about the bigger picture?''', 'Why did you pick that picture?', '{"default":{"topic":"a farm"},"ug":{"topic":"a garden"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L1_C', 'RC2c', 1, 'C', 'Title Selection', 'None', 'Listen to this passage. ''Elephants are very big. They have long trunks. They use their trunks to drink water.'' Which is a better title: ''Drinking Water'' or ''All About Elephants''?', 'Child selects ''All About Elephants''.', 'If they select the detail title, explain that a good title covers everything in the story.', 'Why is ''Drinking Water'' not the best title?', '{"default":{"animal":"Elephants"},"ug":{"animal":"Elephants"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L2_A', 'RC2c', 2, 'A', 'Writing the Main Idea', 'Paper, Pencil, Printed passage', 'Read the passage. What is this passage mostly about? Tell me your answer in one complete sentence, then write it down.', 'Child writes a sentence accurately capturing the main idea.', 'If they write a specific detail, prompt: ''That is one thing that happened. What is the big idea of the whole text?''', 'How do you know that is the main idea?', '{"default":{"topic":"weather"},"ug":{"topic":"the rainy season"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L2_B', 'RC2c', 2, 'B', 'Choosing and Writing a Title', 'Paper, Pencil, Printed passage', 'Read the story. It doesn''t have a title! Think of a title that tells what the story is mostly about. Tell it to me, then write it at the top of the paper.', 'Child provides a relevant title that reflects the main idea.', 'If the title is too narrow, ask them to make it broader to fit the whole story.', 'Why did you choose that title?', '{"default":{"topic":"baking a cake"},"ug":{"topic":"making chapati"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L2_C', 'RC2c', 2, 'C', 'Main Idea vs Detail', 'Paper, Pencil, Printed passage', 'Read the passage. Tell me the main idea. Now tell me one small detail. Write down the main idea sentence.', 'Child distinguishes between the main idea and a detail, and writes the main idea.', 'If they confuse them, explain that the main idea is like the umbrella, and the details are the people standing under it.', 'What makes a detail different from a main idea?', '{"default":{"topic":"dogs"},"ug":{"topic":"cows"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L3_A', 'RC2c', 3, 'A', 'Detecting a Poor Main Idea', 'Printed passage', 'Read the passage. Someone said the main idea is: ''Amara has a red shirt.'' Is that the main idea, or just a small detail?', 'Child identifies that it is a small detail.', 'If they say it''s the main idea, ask: ''Is every sentence about her shirt?''', 'What is the passage ACTUALLY mostly about?', '{"default":{"detail":"red shirt"},"ug":{"detail":"red shirt"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L3_B', 'RC2c', 3, 'B', 'Fixing a Bad Title', 'Printed passage', 'Read this paragraph. The title is ''The Small Ant''. But the paragraph talks about lions, elephants, and zebras! What is wrong with the title, and what should it be?', 'Child recognizes the title doesn''t match the main idea and suggests a better one.', 'If they don''t know, ask them to list what animals are in the text.', 'Why does the title need to match the main idea?', '{"default":{"wrong_title":"The Small Ant"},"ug":{"wrong_title":"The Small Ant"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L3_C', 'RC2c', 3, 'C', 'Spotting the Off-Topic Sentence', 'Printed passage, Pencil', 'Read this paragraph. One of the sentences doesn''t belong because it''s not about the main idea. Find it and cross it out.', 'Child successfully identifies and crosses out the off-topic sentence.', 'If they cross out a valid supporting detail, help them define the main idea first.', 'Why did you cross that sentence out? What is the paragraph actually about?', '{"default":{"topic":"bicycles"},"ug":{"topic":"bicycles"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L4_A', 'RC2c', 4, 'A', 'Writing a Paragraph from a Main Idea', 'Paper, Pencil', 'I will give you a main idea: ''Markets are very busy places.'' Tell me two details that support this. Now write a short paragraph with the main idea first, then your details.', 'Child composes a cohesive paragraph supporting the given main idea.', 'If their details go off-topic, remind them of the main idea sentence.', 'Read your paragraph. Do all your sentences talk about the market being busy?', '{"default":{"topic":"busy markets"},"ug":{"topic":"busy markets in Kampala"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L4_B', 'RC2c', 4, 'B', 'Teaching Main Idea', 'Printed passage, Paper, Pencil', 'Read this passage. Explain to me how you figure out what the main idea is. Write down your steps.', 'Child can articulate a strategy (e.g., look at the first sentence, see what words repeat) and write it down.', 'If they struggle to explain, ask them what they do in their head when asked ''what is it about?''.', 'Why is it helpful to find the main idea when you read?', '{"default":{"topic":"trees"},"ug":{"topic":"mango trees"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L4_C', 'RC2c', 4, 'C', 'Topic Sentence Creation', 'Printed paragraph missing its first sentence, Paper, Pencil', 'Read this paragraph. It is missing its very first sentence (the topic sentence). Think of a sentence that tells the main idea of all the other sentences. Say it, then write it.', 'Child creates an appropriate topic sentence that encapsulates the paragraph.', 'If the sentence is too specific, ask them to make it broader.', 'How did the other sentences help you decide what to write?', '{"default":{"topic":"sports"},"ug":{"topic":"football"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2c_L4_M', 'RC2c', 4, 'M', 'Summarizing a Letter', 'A printed letter, Paper, Pencil', 'Your cousin wrote you this letter. Read it. Then write one sentence to tell me what your cousin is trying to say in the letter.', 'Child reads the letter and synthesizes the main point into a single sentence.', 'Do not correct during the task. If they just list details, review Execute level tasks.', 'Does your sentence tell me the most important reason your cousin wrote the letter?', '{"default":{"relative":"cousin"},"ug":{"relative":"cousin"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L1_A', 'RC2d', 1, 'A', 'Auditory Detail Checking', 'None', 'I''m going to say a main idea: ''Dogs are good pets.'' Which of these sentences is a detail that supports that idea: ''They can learn tricks'' or ''Cats sleep a lot''?', 'Child selects ''They can learn tricks''.', 'If they pick the cat detail, ask if that has anything to do with dogs being good pets.', 'Why does learning tricks make dogs good pets?', '{"default":{"topic":"pets"},"ug":{"topic":"pets"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L1_B', 'RC2d', 1, 'B', 'Physical Sorting of Details', 'Printed passage, 3 sentence strips (2 details from passage, 1 unrelated)', 'Read the passage. Here are three sentences. Two of them are details from the story that support the main idea. One is a trick. Sort them into ''Yes'' and ''No'' piles.', 'Child correctly sorts the supporting details into the Yes pile.', 'If they put the trick sentence in the Yes pile, ask them to find that information in the text.', 'Why did you put that sentence in the ''No'' pile?', '{"default":{"topic":"farming"},"ug":{"topic":"farming maize"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L1_C', 'RC2d', 1, 'C', 'Visual Highlighting', 'Printed passage, Crayon or marker', 'Read this paragraph. The main idea is the very first sentence: ''The market was very loud.'' Find one sentence that gives a detail proving it was loud, and color it in.', 'Child highlights a sentence describing noise (e.g., people shouting, cars honking).', 'If they highlight a sentence about what was sold, ask: ''Does that sentence tell us about the noise?''', 'How does the sentence you colored prove that the market was loud?', '{"default":{"topic":"loud market"},"ug":{"topic":"loud market in Kampala"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L2_A', 'RC2d', 2, 'A', 'Writing a Supporting Detail', 'Paper, Pencil, Printed passage', 'Read the passage. The main idea is ''Elephants are strong.'' Find one detail in the text that shows how strong they are. Tell me the detail, then write it down.', 'Child writes a supporting detail extracted directly from the text.', 'If they make up a detail, redirect them to the text.', 'Show me where you found that detail in the story.', '{"default":{"animal":"Elephants"},"ug":{"animal":"Elephants"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L2_B', 'RC2d', 2, 'B', 'Providing Multiple Details', 'Paper, Pencil, Printed passage', 'Read the passage. The author says ''Amara had a bad day.'' Find TWO details that tell us why her day was bad. Tell them to me, then write them.', 'Child writes two distinct supporting details from the passage.', 'If they only find one, prompt: ''What else went wrong for her?''', 'Do both of those details support the idea that her day was bad?', '{"default":{"character":"Alex"},"ug":{"character":"Amara"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L2_C', 'RC2d', 2, 'C', 'Matching Detail to Main Idea', 'Paper, Pencil, Printed passage', 'Read the passage. It gives three reasons why washing hands is important. Write down the reason that talks about germs.', 'Child successfully locates and writes the specific supporting detail requested.', 'If they write a different reason, remind them we are looking specifically for the one about germs.', 'Why does the author think washing hands is important?', '{"default":{"topic":"washing hands"},"ug":{"topic":"washing hands before eating"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L3_A', 'RC2d', 3, 'A', 'Detecting Irrelevant Details', 'Printed passage', 'Read the paragraph about why sleep is good for you. One of these sentences does not support the main idea: ''Sleep gives you energy'' or ''Beds can be made of wood''. Which one doesn''t belong?', 'Child identifies ''Beds can be made of wood'' as irrelevant to the main idea.', 'If they pick the wrong one, ask: ''Does knowing what a bed is made of tell us why sleep is good?''', 'Why does the sentence about the bed not belong with the others?', '{"default":{"topic":"sleep"},"ug":{"topic":"sleep"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L3_B', 'RC2d', 3, 'B', 'Fixing a Weak Argument', 'Printed passage, Paper, Pencil', 'Read this paragraph. The author wants to prove that ''Lions are dangerous''. But their supporting detail says ''Lions have fur.'' That doesn''t prove they are dangerous! Find a better detail in the text and write it down.', 'Child selects a detail like ''they have sharp teeth'' and writes it.', 'If they still pick a weak detail, ask: ''Does having fur make something dangerous? A rabbit has fur.''', 'How does your new detail do a better job of proving the main idea?', '{"default":{"animal":"Lions"},"ug":{"animal":"Lions"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L3_C', 'RC2d', 3, 'C', 'Evaluating Fact vs Inference', 'Printed passage', 'Read the story. The main idea is ''Tendo was hungry.'' Did the author write the detail ''his stomach growled'', or did you just guess that because he was hungry?', 'Child accurately distinguishes whether the detail was explicitly stated in the text.', 'If they assume it was in the text without checking, tell them to point to the exact words.', 'Is it a supporting detail if the author didn''t actually write it down?', '{"default":{"character":"Sam"},"ug":{"character":"Tendo"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L4_A', 'RC2d', 4, 'A', 'Brainstorming Details', 'Paper, Pencil', 'I will give you a main idea: ''School is a busy place.'' Think of three details that prove this is true. Say them, then write them down.', 'Child generates three relevant supporting details independently.', 'If details are off-topic, repeat the main idea statement.', 'How do your details prove that school is busy?', '{"default":{"topic":"school"},"ug":{"topic":"school"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L4_B', 'RC2d', 4, 'B', 'Adding a Detail to a Text', 'Printed passage, Paper, Pencil', 'Read this paragraph about why eating fruit is healthy. It has two supporting details. Think of a third detail that could be added to make the paragraph stronger. Write it down.', 'Child composes a relevant supporting detail that fits the existing text.', 'If the detail contradicts the text, ask them to re-read what is already there.', 'Where would your new sentence fit best in the paragraph?', '{"default":{"topic":"fruit"},"ug":{"topic":"fruit like mangoes and jackfruit"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L4_C', 'RC2d', 4, 'C', 'Defending a Statement', 'Printed passage', 'Read the story. I think the main character was very brave. You have to prove me right by finding three details in the text that show bravery. Tell them to me.', 'Child successfully orally extracts three supporting details to defend the premise.', 'If they struggle, ask: ''What did the character do when they saw the snake?''', 'Do you think the author wanted us to think the character was brave? Why?', '{"default":{"theme":"bravery"},"ug":{"theme":"bravery near the river"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2d_L4_M', 'RC2d', 4, 'M', 'Extracting Evidence', 'A printed advertisement or flyer, Paper, Pencil', 'Here is a flyer for a new bicycle. The flyer says this is the ''best bike ever.'' Read it and write down two reasons the flyer gives to prove it is the best.', 'Child extracts two supporting details used as evidence in the flyer.', 'Do not correct during the task. If they fail, review supporting details.', 'Did the flyer give good reasons, or just say it was the best without proving it?', '{"default":{"item":"bicycle"},"ug":{"item":"bicycle"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L1_A', 'RC2e', 1, 'A', 'Auditory Cause Identification', 'None', 'Listen to this sentence: ''Because it rained heavily, the road was muddy.'' What made the road muddy?', 'Child identifies the heavy rain as the cause.', 'If they say ''the road'', clarify: ''The road is muddy, but WHY did it get muddy?''', 'What word gives us a clue that we are hearing a cause?', '{"default":{"event":"rain and mud"},"ug":{"event":"heavy rain and muddy roads"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L1_B', 'RC2e', 1, 'B', 'Physical Matching (Cause to Effect)', 'Printed passage, Picture cards: one of rain, one of a puddle, one of sun, one of a dry plant', 'I''m going to read a story. When I''m done, match the picture of the ''cause'' (what happened first) to the picture of the ''effect'' (what happened because of it).', 'Child successfully matches cause and effect pairs.', 'If they match incorrectly, review the timeline of the story.', 'Why did the puddle form?', '{"default":{"theme":"weather"},"ug":{"theme":"weather"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L1_C', 'RC2e', 1, 'C', 'Verbal Effect Prediction', 'None', 'Listen to this part of a story: ''Tendo forgot to close the gate to the goat pen.'' What do you think the effect of that will be? What will happen next?', 'Child provides a logical prediction (e.g., the goats will get out).', 'If the prediction is illogical, ask what goats usually do when a gate is open.', 'Why would the goats leaving be an effect of the open gate?', '{"default":{"animal":"dog"},"ug":{"animal":"goats"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L2_A', 'RC2e', 2, 'A', 'Writing the Cause', 'Paper, Pencil, Printed passage', 'Read the story. The effect is that Amara was late for school. Find the sentence that tells us WHY she was late. Say it, then write it down.', 'Child identifies the cause and writes it accurately.', 'If they write that she was late, say: ''That is the effect. We need the reason why.''', 'What word did the author use to show the cause?', '{"default":{"character":"Alex","reason":"missed the bus"},"ug":{"character":"Amara","reason":"had to fetch water"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L2_B', 'RC2e', 2, 'B', 'Writing the Effect', 'Paper, Pencil, Printed passage', 'Read the story. The cause is that the boy dropped his glass of milk. What was the effect? What happened because he dropped it? Say it, then write it.', 'Child identifies the effect (e.g., the glass broke, milk spilled) and writes it.', 'If they write ''he dropped it'', remind them we are looking for the result.', 'What happened right after the glass fell?', '{"default":{"event":"dropping milk"},"ug":{"event":"dropping a cup of tea"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L2_C', 'RC2e', 2, 'C', 'Connecting Cause and Effect', 'Paper, Pencil, Printed passage', 'Read the passage. Write one sentence that has both the cause and the effect. Use the word ''because''. Tell me the sentence first.', 'Child constructs a cohesive ''because'' sentence linking the cause and effect found in the text.', 'If they put the effect after ''because'' (e.g., he was sad because he cried), guide them to swap the order.', 'Does your sentence explain WHY the thing happened?', '{"default":{"event":"lost a toy"},"ug":{"event":"lost a coin"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L3_A', 'RC2e', 3, 'A', 'Reversing Cause and Effect', 'Printed passage', 'Read the story. Someone said, ''The floor got wet because the boy slipped.'' Wait, is that right? Did slipping cause the wet floor, or did the wet floor cause the slipping?', 'Child correctly identifies that the wet floor is the cause and slipping is the effect.', 'If they agree with the prompt, have them trace the events in order from the text.', 'Why does the order of cause and effect matter?', '{"default":{"event":"slipping on water"},"ug":{"event":"slipping in the mud"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L3_B', 'RC2e', 3, 'B', 'Spotting the Missing Cause', 'Printed passage', 'Read this paragraph. It says ''The plant died.'' But the author forgot to tell us WHY! Read it carefully—is the cause in the text, or is it missing?', 'Child recognizes that the text states an effect without providing the cause.', 'If they guess a cause (e.g., ''it didn''t get water''), tell them: ''You are smart to guess that, but did the author actually write it?''', 'How does a story feel when the author gives an effect but no cause?', '{"default":{"event":"plant dying"},"ug":{"event":"maize drying up"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L3_C', 'RC2e', 3, 'C', 'Evaluating ''So'' and ''Because''', 'Printed passage, Paper, Pencil', 'Look at this sentence: ''It was dark, because we turned on the lamp.'' That doesn''t make sense. Should the word be ''because'' or ''so''? Fix the sentence and write it.', 'Child identifies the incorrect conjunction and rewrites using ''so'' (or swaps the clauses).', 'If they struggle, explain that ''because'' introduces the cause, and ''so'' introduces the effect.', 'How does changing that one word fix the sentence?', '{"default":{"event":"dark and lamp"},"ug":{"event":"dark and lantern"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L4_A', 'RC2e', 4, 'A', 'Generating Causes', 'Paper, Pencil', 'I will give you an effect: ''The dog barked loudly.'' Think of two different causes for why the dog might have barked. Write them down in full sentences.', 'Child generates two plausible causes for the given effect.', 'If the causes don''t make sense, prompt: ''What makes a dog bark in real life?''', 'Which of those causes do you think is more likely to happen?', '{"default":{"animal":"dog"},"ug":{"animal":"dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L4_B', 'RC2e', 4, 'B', 'Generating Effects', 'Paper, Pencil', 'I will give you a cause: ''The wind blew very hard.'' Think of an effect that could happen because of that. Tell it to me, then write a sentence using the word ''so''.', 'Child generates a plausible effect and uses ''so'' correctly in a sentence.', 'If they use ''because'', ask them to rephrase to start with the cause (The wind blew hard, so...).', 'What word did you use to connect the cause to the effect?', '{"default":{"cause":"strong wind"},"ug":{"cause":"strong wind before the rain"}}', 0);